record_types.code:
type Epoll_Event is record
   Flags : Epoll_Flags := (others => False);
   Data  : Unsigned_64 := -1;
end record;

type Epoll_Flags is record
   Readable       : Boolean;
   Writable       : Boolean;
   Peer_Shutdown  : Boolean;
   Out_Of_Band    : Boolean;
   Error          : Boolean;
   Hang_Up        : Boolean;
   Edge_Triggered : Boolean;
   One_Shot       : Boolean;
   Wake_Up        : Boolean;
   Exclusive      : Boolean;
end record;

subprograms.code:
procedure Control
   (This   : Epoll_Descriptor;
    Socket : Socket_Type;
    Op     : Epoll_Operation;
    Event  : access Epoll_Event)

function Wait
   (This       : Epoll_Descriptor;
    Max_Events : Positive := 1;
    Timeout    : Integer := -1)
    return Epoll_Events
